/*! MO 自包含 CODE128 条码生成器 — 零依赖，兼容 JsBarcode(elem, text, opts) 基本用法
    支持 CODE128(自动 B/C 切换)。用于在 SVG 元素上绘制条形码。 */
(function (global) {
  'use strict';

  // CODE128 编码表（107 个图案，每个图案 6 位：3 黑条3 白条 的宽度序列）
  var PATTERNS = [
    "212222","222122","222221","121223","121322","131222","122213","122312","132212","221213",
    "221312","231212","112232","122132","122231","113222","123122","123221","223211","221132",
    "221231","213212","223112","312131","311222","321122","321221","312212","322112","322211",
    "212123","212321","232121","111323","131123","131321","112313","132113","132311","211313",
    "231113","231311","112133","112331","132131","113123","113321","133121","313121","211331",
    "231131","213113","213311","213131","311123","311321","331121","312113","312311","332111",
    "314111","221411","431111","111224","111422","121124","121421","141122","141221","112214",
    "112412","122114","122411","142112","142211","241211","221114","413111","241112","134111",
    "111242","121142","121241","114212","124112","124211","411212","421112","421211","212141",
    "214121","412121","111143","111341","131141","114113","114311","411113","411311","113141",
    "114131","311141","411131","211412","211214","211232","2331112"
  ];
  var STARTB = 104, STARTC = 99, STOP = 106, FNC_CODEC = 99, FNC_CODEB = 100;

  function encode128(text) {
    // 简单策略：纯数字且长度为偶数→用 CODE C（更紧凑）；否则用 CODE B
    var codes = [];
    var useC = /^\d+$/.test(text) && text.length % 2 === 0 && text.length >= 4;
    if (useC) {
      codes.push(STARTC);
      for (var i = 0; i < text.length; i += 2) {
        codes.push(parseInt(text.substr(i, 2), 10));
      }
    } else {
      codes.push(STARTB);
      for (var j = 0; j < text.length; j++) {
        var c = text.charCodeAt(j) - 32; // CODE B: 可见 ASCII 从空格(32)开始 → 值0
        if (c < 0 || c > 94) c = 0; // 不支持的字符用空格代替
        codes.push(c);
      }
    }
    // 校验位
    var sum = codes[0];
    for (var k = 1; k < codes.length; k++) sum += codes[k] * k;
    codes.push(sum % 103);
    codes.push(STOP);
    // 拼图案
    var seq = "";
    for (var m = 0; m < codes.length; m++) seq += PATTERNS[codes[m]];
    return seq; // 一串数字，奇数位=黑条宽，偶数位=白条宽（交替，从黑开始）
  }

  function draw(elem, text, opts) {
    opts = opts || {};
    var width = opts.width || 2;          // 单位条宽(px)
    var height = opts.height || 60;        // 条码高度
    var margin = (opts.margin != null) ? opts.margin : 10;
    var displayValue = opts.displayValue !== false;
    var fontSize = opts.fontSize || 16;
    var textMargin = 4;

    var seq = encode128(String(text));
    // 计算总宽
    var total = 0, i;
    for (i = 0; i < seq.length; i++) total += parseInt(seq[i], 10);
    var barsWidth = total * width;
    var svgW = barsWidth + margin * 2;
    var textH = displayValue ? (fontSize + textMargin) : 0;
    var svgH = height + margin * 2 + textH;

    var svgNS = "http://www.w3.org/2000/svg";
    // elem 可以是 SVG 元素或选择器字符串
    var node = (typeof elem === 'string') ? document.querySelector(elem) : elem;
    if (!node) return;
    // 清空
    while (node.firstChild) node.removeChild(node.firstChild);
    node.setAttribute("width", svgW);
    node.setAttribute("height", svgH);
    node.setAttribute("viewBox", "0 0 " + svgW + " " + svgH);

    // 白底
    var bg = document.createElementNS(svgNS, "rect");
    bg.setAttribute("x", 0); bg.setAttribute("y", 0);
    bg.setAttribute("width", svgW); bg.setAttribute("height", svgH);
    bg.setAttribute("fill", opts.background || "#ffffff");
    node.appendChild(bg);

    // 画条：从黑开始，奇偶交替
    var x = margin, black = true;
    for (i = 0; i < seq.length; i++) {
      var w = parseInt(seq[i], 10) * width;
      if (black) {
        var bar = document.createElementNS(svgNS, "rect");
        bar.setAttribute("x", x);
        bar.setAttribute("y", margin);
        bar.setAttribute("width", w);
        bar.setAttribute("height", height);
        bar.setAttribute("fill", opts.lineColor || "#000000");
        node.appendChild(bar);
      }
      x += w; black = !black;
    }

    // 文字
    if (displayValue) {
      var t = document.createElementNS(svgNS, "text");
      t.setAttribute("x", svgW / 2);
      t.setAttribute("y", margin + height + textMargin + fontSize - 2);
      t.setAttribute("text-anchor", "middle");
      t.setAttribute("font-family", opts.font || "monospace");
      t.setAttribute("font-size", fontSize);
      t.setAttribute("fill", opts.lineColor || "#000000");
      t.textContent = String(text);
      node.appendChild(t);
    }
  }

  // 兼容 JsBarcode 的调用方式：JsBarcode(elem, text, options)
  function JsBarcode(elem, text, options) {
    // 支持选择器或元素；忽略链式调用的高级用法（够本系统使用）
    draw(elem, text, options || {});
    return JsBarcode;
  }
  // 兼容 .init() 之类的空调用
  JsBarcode.init = function () {};

  global.JsBarcode = JsBarcode;
  if (typeof module !== 'undefined' && module.exports) module.exports = JsBarcode;

})(typeof window !== 'undefined' ? window : this);
